sql:
SELECT week_start, total_cases
FROM weekly_data
ORDER BY week_start ASC;

SELECT total_cases
FROM weekly_data
WHERE week = 10 AND year = 2023;

SELECT AVG(cases_vaxxed) AS average_cases_vaxxed
FROM weekly_data
WHERE year = 2023;

external_knowledge:
- The "weekly health situation" encompasses the total cases and hospitalizations, the rates of these among vaccinated and unvaccinated populations, vaccination statistics, and details about hospitalization length and ICU admissions;
- "Doses administered" refers to the total number of vaccine doses given in each region, including first, second, and booster doses;
- "Hospitalization stays" include the average length of stay for patients and the total number of ICU admissions.

sql:
SELECT COUNT(*) AS fully_vaccinated_count
FROM vaccination_data
WHERE region_id = 1 AND vaccination_status = 'fully vaccinated';

external_knowledge:
- "storm clouds gathering" refers to the increasing number of cases and hospitalizations;
- "caught in the tempest of illness" refers to the total number of cases;
- "swept away into the hospital beds" refers to the total number of hospitalizations.

sql:
SELECT year, week, cases_vaxxed_rate, cases_unvaxxed_rate
FROM weekly_data
ORDER BY year, week;

SELECT week_start, cases_vaxxed, cases_unvaxxed, hosp_vaxxed_rate, hosp_unvaxxed_rate
FROM weekly_data
ORDER BY week_start ASC;

external_knowledge:
- 'hospitalizations' refer to instances of patients being admitted to hospitals;
- 'average hospitalizations' indicate the mean number of admissions for each specified period;
- 'typical average' refers to the calculated mean of the averages for each region and year;
- 'regions' correspond to geographical areas where the hospital data is collected.

sql:
SELECT year, week, region_id, cases_vaxxed
FROM weekly_data
ORDER BY year, week;

SELECT region_name, population
FROM regions
ORDER BY population DESC;

SELECT AVG(w.cases_vaxxed) AS average_cases_vaxxed
FROM weekly_data w
INNER JOIN vaccination_data v ON w.region_id = v.region_id;
